$ErrorActionPreference = "Stop"

$root = (Resolve-Path (Join-Path $PSScriptRoot "..")).Path
$assets = Join-Path $root "diploma_assets"
$pptPath = Join-Path $root "Презентация_предзащита_Пеньшин.pptx"
$docPath = Join-Path $root "Текст_к_презентации_Пеньшин.docx"

function Pt([double]$inches) { return $inches * 72 }

function Add-Title($slide, [string]$title) {
  $shape = $slide.Shapes.AddTextbox(1, (Pt 0.55), (Pt 0.28), (Pt 12.2), (Pt 0.55))
  $shape.TextFrame.TextRange.Text = $title
  $shape.TextFrame.TextRange.Font.Name = "Segoe UI Semibold"
  $shape.TextFrame.TextRange.Font.Size = 24
  $shape.TextFrame.TextRange.Font.Color.RGB = 0x1F2937
}

function Add-Subtitle($slide, [string]$text) {
  $shape = $slide.Shapes.AddTextbox(1, (Pt 0.65), (Pt 0.92), (Pt 11.8), (Pt 0.45))
  $shape.TextFrame.TextRange.Text = $text
  $shape.TextFrame.TextRange.Font.Name = "Segoe UI"
  $shape.TextFrame.TextRange.Font.Size = 13
  $shape.TextFrame.TextRange.Font.Color.RGB = 0x4B5563
}

function Add-Bullets($slide, [string[]]$items, [double]$x, [double]$y, [double]$w, [double]$h, [int]$fontSize = 17) {
  $shape = $slide.Shapes.AddTextbox(1, (Pt $x), (Pt $y), (Pt $w), (Pt $h))
  $shape.TextFrame.MarginLeft = 8
  $shape.TextFrame.MarginRight = 8
  $shape.TextFrame.MarginTop = 5
  $shape.TextFrame.MarginBottom = 5
  $shape.TextFrame.TextRange.Text = ($items -join "`r")
  $shape.TextFrame.TextRange.Font.Name = "Segoe UI"
  $shape.TextFrame.TextRange.Font.Size = $fontSize
  $shape.TextFrame.TextRange.Font.Color.RGB = 0x111827
  for ($i = 1; $i -le $shape.TextFrame.TextRange.Paragraphs().Count; $i++) {
    $p = $shape.TextFrame.TextRange.Paragraphs($i)
    $p.ParagraphFormat.Bullet.Visible = $true
    $p.ParagraphFormat.Bullet.Character = 8226
  }
  return $shape
}

function Add-Card($slide, [string]$title, [string]$body, [double]$x, [double]$y, [double]$w, [double]$h, [int]$fill = 0xF8FAFC) {
  $shape = $slide.Shapes.AddShape(5, (Pt $x), (Pt $y), (Pt $w), (Pt $h))
  $shape.Fill.ForeColor.RGB = $fill
  $shape.Line.ForeColor.RGB = 0xCBD5E1
  $shape.TextFrame.MarginLeft = 12
  $shape.TextFrame.MarginRight = 12
  $shape.TextFrame.MarginTop = 8
  $shape.TextFrame.TextRange.Text = "$title`r$body"
  $shape.TextFrame.TextRange.Font.Name = "Segoe UI"
  $shape.TextFrame.TextRange.Font.Size = 13
  $shape.TextFrame.TextRange.Font.Color.RGB = 0x111827
  $shape.TextFrame.TextRange.Paragraphs(1).Font.Name = "Segoe UI Semibold"
  $shape.TextFrame.TextRange.Paragraphs(1).Font.Size = 17
  return $shape
}

function Add-FitPicture($slide, [string]$file, [double]$x, [double]$y, [double]$w, [double]$h) {
  $path = Join-Path $assets $file
  if (!(Test-Path -LiteralPath $path)) { return $null }
  $pic = $slide.Shapes.AddPicture($path, $false, $true, (Pt $x), (Pt $y), -1, -1)
  $maxW = Pt $w
  $maxH = Pt $h
  $scale = [Math]::Min($maxW / $pic.Width, $maxH / $pic.Height)
  $pic.Width = $pic.Width * $scale
  $pic.Height = $pic.Height * $scale
  $pic.Left = (Pt $x) + (($maxW - $pic.Width) / 2)
  $pic.Top = (Pt $y) + (($maxH - $pic.Height) / 2)
  return $pic
}

function Add-Connector($slide, $from, $to) {
  $x1 = $from.Left + $from.Width
  $y1 = $from.Top + ($from.Height / 2)
  $x2 = $to.Left
  $y2 = $to.Top + ($to.Height / 2)
  $line = $slide.Shapes.AddConnector(1, $x1, $y1, $x2, $y2)
  $line.Line.ForeColor.RGB = 0x374151
  $line.Line.Weight = 1.5
  $line.Line.EndArrowheadStyle = 3
  return $line
}

function Add-Slide($ppt, [string]$title, [string]$subtitle = "") {
  $slide = $ppt.Slides.Add($ppt.Slides.Count + 1, 12)
  $slide.Background.Fill.ForeColor.RGB = 0xFFFFFF
  Add-Title $slide $title
  if ($subtitle) { Add-Subtitle $slide $subtitle }
  return $slide
}

function Add-ProgramFlow($slide) {
  $a = Add-Card $slide "Вход" "email + пароль" 0.7 1.45 2.0 0.78 0xDBEAFE
  $b = Add-Card $slide "JWT" "выдача токена" 3.05 1.45 2.0 0.78 0xE0F2FE
  $c = Add-Card $slide "Проверка роли" "student / teacher / admin" 5.4 1.45 2.15 0.78 0xFEF3C7
  $d = Add-Card $slide "Учебный контекст" "курс, задание, тест" 7.95 1.45 2.25 0.78 0xDCFCE7
  $e = Add-Card $slide "Сохранение" "SQLite + uploads" 10.65 1.45 2.0 0.78 0xEDE9FE
  Add-Connector $slide $a $b | Out-Null
  Add-Connector $slide $b $c | Out-Null
  Add-Connector $slide $c $d | Out-Null
  Add-Connector $slide $d $e | Out-Null

  $s = Add-Card $slide "Студент" "курсы, задания, тесты, результаты" 0.9 3.25 3.4 1.0 0xEFF6FF
  $t = Add-Card $slide "Преподаватель" "курсы, тесты, проверки, журнал" 4.95 3.25 3.4 1.0 0xECFDF5
  $adm = Add-Card $slide "Администратор" "пользователи, группы, роли" 9.0 3.25 3.4 1.0 0xFFFBEB
  $core = Add-Card $slide "Единый программный контур LMS" "API связывает действия пользователей с базой данных, файлами, журналом и аналитикой" 2.2 5.25 8.9 1.0 0xF8FAFC
  foreach ($role in @($s, $t, $adm)) {
    $line = $slide.Shapes.AddConnector(1, $role.Left + ($role.Width / 2), $role.Top + $role.Height, $core.Left + ($core.Width / 2), $core.Top)
    $line.Line.ForeColor.RGB = 0x374151
    $line.Line.Weight = 1.25
    $line.Line.EndArrowheadStyle = 3
  }
}

